Generics enable type-safe reusable code without casting.

```java
// Generic class
class Pair<A, B> {
  final A first; final B second;
  Pair(A a, B b) { first = a; second = b; }
}

// Bounded type parameter
<T extends Comparable<T>> T max(T a, T b) {
  return a.compareTo(b) >= 0 ? a : b;
}

// Wildcards (PECS: Producer Extends, Consumer Super)
void readAll(List<? extends Number> list) {
  for (Number n : list) System.out.println(n); // read only
}
void addNumbers(List<? super Integer> list) {
  list.add(42); // write only
}

// Type erasure: generics exist only at compile time
// List<String> and List<Integer> are both List at runtime
// Cannot do: new T(), instanceof List<String>, T[]

class Box<T> {
  T value;
  Box(T v) { value = v; }
  <R> Box<R> map(Function<T,R> f) { return new Box<>(f.apply(value)); }

