These patterns appear constantly in Java interviews — knowing them cold is mandatory.

```java
// equals + hashCode contract: equal objects must have equal hashes
class Point {
  final int x, y;
  Point(int x, int y) { this.x = x; this.y = y; }

  @Override public boolean equals(Object o) {
    if (this == o) return true;
    if (!(o instanceof Point p)) return false;
    return x == p.x && y == p.y;
  }
  @Override public int hashCode() {
    return Objects.hash(x, y);
  }
}

// Comparable for natural ordering
class Employee implements Comparable<Employee> {
  String name; double salary;
  public int compareTo(Employee other) {
    return Double.compare(this.salary, other.salary);
  }
}
list.sort(Comparator.comparing(Employee::getName)
  .thenComparingDouble(Employee::getSalary).reversed());

// Immutable class recipe
final class Money {
  private final long cents;
  private final String currency;
  Money(long cents, String currency) {
    this.cents = cents;
    this.currency = Objects.requireNonNull(currency);
  }
  Money add(Money other) { return new Money(cents+other.cents, currency); }
}

// Builder pattern
